USE safewalk;

SET FOREIGN_KEY_CHECKS = 0;
TRUNCATE TABLE score_history;
TRUNCATE TABLE street_safety_scores;
TRUNCATE TABLE reports;
SET FOREIGN_KEY_CHECKS = 1;

DROP PROCEDURE IF EXISTS upgrade_table;
DELIMITER //
CREATE PROCEDURE upgrade_table()
BEGIN
  DECLARE CONTINUE HANDLER FOR SQLEXCEPTION BEGIN END;
  ALTER TABLE street_safety_scores ADD COLUMN geometry JSON;
END //
DELIMITER ;
CALL upgrade_table();









SELECT COUNT(*) as total_streets FROM street_safety_scores;
SELECT COUNT(*) as total_reports FROM reports;
SELECT AVG(score) as avg_safety_score FROM street_safety_scores;
SELECT street_name, score FROM street_safety_scores ORDER BY score ASC LIMIT 10;
